function dig(x){ if(x==null)return''; if(typeof x==='string')return x; if(typeof x==='object'){ if(x.agent!==undefined)return String(x.agent); for(const k of ['some_input','query','input','text','value']) if(x[k]!==undefined) return dig(x[k]); const v=Object.values(x); if(v.length) return dig(v[0]); } return ''; }
function whichAgent(a){ a=String(a||'').toLowerCase(); if(/\b002\b|win/.test(a))return'002'; if(/\b001\b|ubuntu.?2|ubuntu2/.test(a))return'001'; if(/\b000\b|manager|\bubuntu\b/.test(a))return'000'; return ''; }

const ag=whichAgent(dig($input.first().json||{}));
const fs=require('fs'); let data;
try{ data=JSON.parse(fs.readFileSync('/home/node/.n8n/socview/bans.json','utf8')); }
catch(e){ return [{json:{result:'[collecte bans indisponible: '+e.message+']'}}]; }
const ags=data.agents||{};
function fmt(id){ const x=ags[id]||{}; const b=x.banned_ips||[]; if(!b.length) return id+' ('+(x.name||'')+'): aucune IP bannie  ['+(x.source||'')+']'; return id+' ('+(x.name||'')+'): '+b.map(z=>z.ip).join(', ')+'  ['+(x.source||'')+']'; }
const ids=ag?[ag]:['000','001','002'];
return [{json:{result:'IP actuellement bannies (etat reel du pare-feu, collecte '+(data.generated_at||'?')+'):\n'+ids.map(fmt).join('\n')+'\n(soar_status = journal SOAR ; ceci = etat live du pare-feu)'}}];
